SELECT AVG(value) AS average_metric_value
FROM population_health_metrics
WHERE year = 2023;

SELECT validation_status
FROM data_validation_logs
WHERE metric_id = 1;

SELECT value
FROM population_health_metrics
WHERE ref_area = 'usa' AND year = 2023;

SELECT COUNT(metric_id) AS passed_metrics_count
FROM data_validation_logs
WHERE validation_status = 'passed';

SELECT MAX(value) AS max_metric_value
FROM population_health_metrics
WHERE year = 2021;

SELECT AVG(value) AS average_value
FROM population_health_metrics
WHERE year = 2023 AND ref_area = 'afg';

SELECT AVG(value) AS average_value
FROM population_health_metrics
WHERE ref_area = 'afg' AND year = 2023;
